module SR_latch (
    input wire S,
    input wire R,
    output reg obf_Q,
    output reg Q_bar
);
    always @(S, R) begin
        if (S && !R) begin
            obf_Q <= 1;
            Q_bar <= 0;
        end else if (!S && R) begin
            obf_Q <= 0;
            Q_bar <= 1;
        end
        // Maintain state when both S and R are low
    end
endmodule
